window.HK2_LC5 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["A woman is putting on a hat.", "A woman is relaxing beneath some trees.", "A woman is jogging along a trail.", "A woman is skiing on the snow."], "optko": ["한 여자가 모자를 쓰고 있는 중이다.", "한 여자가 나무들 아래에서 휴식을 취하고 있다.", "한 여자가 오솔길을 따라 조깅하고 있다.", "한 여자가 눈 위에서 스키를 타고 있다."], "ans": 2, "audio": "Test05_01.mp3", "img": "hk2_t5_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["The women are sipping their drinks.", "The women are posing for a picture.", "One of the women is setting up camera equipment.", "One of the women is unwrapping a gift."], "optko": ["여자들이 음료를 조금씩 마시고 있다.", "여자들이 사진을 위해 포즈를 취하고 있다.", "여자들 중 한 명이 카메라 장비를 설치하고 있다.", "여자들 중 한 명이 선물을 풀고 있다."], "ans": 1, "audio": "Test05_02.mp3", "img": "hk2_t5_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["Some people are exiting a greenhouse.", "Bouquets are being sold at an outdoor market.", "A customer is talking with a florist.", "Women are browsing plants."], "optko": ["몇몇 사람들이 온실을 나가고 있다.", "꽃다발들이 야외 시장에서 팔리고 있다.", "한 손님이 꽃집 주인과 이야기하고 있다.", "여자들이 식물들을 둘러보고 있다."], "ans": 3, "audio": "Test05_03.mp3", "img": "hk2_t5_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["An apron is hanging from a hook.", "Shelves have been stocked with merchandise.", "The man is buying items at a cash register.", "The man is removing jars from a basket."], "optko": ["앞치마가 고리에 걸려 있다.", "선반들이 물품들로 채워져 있다.", "남자가 계산대에서 물품을 사고 있다.", "남자가 바구니에서 병들을 치우고 있다."], "ans": 1, "audio": "Test05_04.mp3", "img": "hk2_t5_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Vehicles are on display at a dealership.", "A multi-level structure surrounds a parking lot.", "Windows overlook a garden area.", "Water is spraying from a fountain."], "optko": ["차량들이 대리점에 전시되어 있다.", "다층 건물이 주차장을 둘러싸고 있다.", "창문들이 정원을 내려다보고 있다.", "물이 분수에서 뿌려지고 있다."], "ans": 1, "audio": "Test05_05.mp3", "img": "hk2_t5_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Some people are sitting on stones.", "One of the people is walking up a hill.", "An airplane is taking off from a runway.", "Some pedestrians are photographing the jets."], "optko": ["몇몇 사람들이 돌 위에 앉아 있다.", "사람들 중 한 명이 언덕을 걸어 오르고 있다.", "비행기가 활주로에서 이륙하고 있다.", "몇몇 보행자들이 제트기들의 사진을 찍고 있다."], "ans": 0, "audio": "Test05_06.mp3", "img": "hk2_t5_q6.jpg"}, {"n": 7, "part": 2, "q": "When are you planning to revise the schedule?", "qko": "일정을 언제 수정할 계획인가요?", "opts": ["If you can help me.", "A daily work plan.", "Later this afternoon."], "optko": ["당신이 저를 도울 수 있다면요.", "일일 근무 계획이요.", "오늘 오후 늦게요."], "ans": 2, "audio": "Test05_07.mp3"}, {"n": 8, "part": 2, "q": "Who posted the recent announcement?", "qko": "최근 공지를 누가 게시했나요?", "opts": ["About a meeting.", "The secretary did.", "Yes, it's on the bulletin board."], "optko": ["회의에 관해서요.", "비서가 했어요.", "네, 그건 게시판에 있어요."], "ans": 1, "audio": "Test05_08.mp3"}, {"n": 9, "part": 2, "q": "How do you usually get to the mall?", "qko": "쇼핑몰에 보통 어떻게 가시나요?", "opts": ["Only about 30 minutes.", "I take a taxi.", "To return some shoes."], "optko": ["약 30분 정도밖에요.", "저는 택시를 타요.", "신발들을 반품하려고요."], "ans": 1, "audio": "Test05_09.mp3"}, {"n": 10, "part": 2, "q": "Excuse me. Is this seat taken?", "qko": "실례합니다. 이 자리에 주인이 있나요?", "opts": ["It's not very comfortable.", "I don't think so.", "Please take only one pamphlet."], "optko": ["그건 별로 편안하지 않아요.", "아닌 것 같아요.", "소책자를 하나만 가져가 주세요."], "ans": 1, "audio": "Test05_10.mp3"}, {"n": 11, "part": 2, "q": "A holiday promotion is being offered now, right?", "qko": "휴일 판촉이 지금 제공되고 있죠, 그렇죠?", "opts": ["The correct confirmation code.", "Yes, I was promoted.", "No, it starts this weekend."], "optko": ["정확한 확인 코드요.", "네, 저는 승진되었어요.", "아니요, 그것은 이번 주말에 시작해요."], "ans": 2, "audio": "Test05_11.mp3"}, {"n": 12, "part": 2, "q": "Where is the new art gallery going to be opened?", "qko": "새로운 미술관은 어디에서 개장될 예정인가요?", "opts": ["We close daily at 10 P.M.", "In SoHo, most likely.", "Art school was a great experience."], "optko": ["저희는 매일 오후 10시에 닫습니다.", "아마도 소호일 것 같아요.", "미술 학교는 정말 좋은 경험이었어요."], "ans": 1, "audio": "Test05_12.mp3"}, {"n": 13, "part": 2, "q": "How long are these batteries supposed to last?", "qko": "이 건전지들은 얼마나 오래 지속되나요?", "opts": ["Up to four months.", "No, it was the first one I bought.", "For my digital camera."], "optko": ["넉 달까지요.", "아니요, 그건 제가 처음으로 산 거예요.", "제 디지털카메라를 위해서요."], "ans": 0, "audio": "Test05_13.mp3"}, {"n": 14, "part": 2, "q": "Can you meet Mr. Lee at the train station?", "qko": "기차역에서 Mr. Lee를 만나주실 수 있나요?", "opts": ["You'd better hurry then.", "Sorry, but my car is out of gas.", "We trained for six weeks."], "optko": ["그렇다면 당신은 서두르는 게 좋겠어요.", "죄송하지만, 제 자동차에 기름이 떨어졌어요.", "우리는 6주 동안 교육받았어요."], "ans": 1, "audio": "Test05_14.mp3"}, {"n": 15, "part": 2, "q": "What company are you writing for now?", "qko": "당신은 지금 어느 회사에 기고하고 있나요?", "opts": ["The Leland Publishing Firm.", "I sent him an e-mail about that.", "I'm not sure they received the letter."], "optko": ["Leland 출판사요.", "저는 그것에 관해서 그에게 이메일을 보냈어요.", "그들이 편지를 받았는지 확실히 모르겠어요."], "ans": 0, "audio": "Test05_15.mp3"}, {"n": 16, "part": 2, "q": "Have you been to the Thai restaurant next to the subway station?", "qko": "지하철역 옆에 있는 태국 음식점에 가본 적 있나요?", "opts": ["Sure. I can recommend several.", "A chef will be arriving shortly.", "Not yet, but I'd like to go."], "optko": ["물론이죠. 제가 몇 개 추천해드릴 수 있어요.", "주방장이 곧 도착할 거예요.", "아직이요, 하지만 가보고 싶어요."], "ans": 2, "audio": "Test05_16.mp3"}, {"n": 17, "part": 2, "q": "Why aren't employees getting bonuses this quarter?", "qko": "직원들은 왜 이번 분기에 상여금을 받지 않나요?", "opts": ["Yes, sometime in December.", "Because the company can't afford it.", "A promotion as well."], "optko": ["네, 12월 중에요.", "회사가 형편이 안되기 때문이에요.", "승진도요."], "ans": 1, "audio": "Test05_17.mp3"}, {"n": 18, "part": 2, "q": "When do you expect to begin staff evaluations?", "qko": "언제 직원 평가를 시작할 예정인가요?", "opts": ["Oh, probably not until next Monday.", "I'll be leaving at 7 o'clock.", "We don't expect any problems."], "optko": ["아, 아마도 다음 월요일이나 되어야 할 거예요.", "저는 7시에 떠날 거예요.", "우리는 어떤 문제도 예상하지 않아요."], "ans": 0, "audio": "Test05_18.mp3"}, {"n": 19, "part": 2, "q": "Who was the keynote speaker at the agricultural conference?", "qko": "농업 학회에서 누가 기조연설자였나요?", "opts": ["Mr. Lowe is talking to some clients.", "The owner of an organic farm.", "At an agricultural association."], "optko": ["Mr. Lowe는 몇몇 고객들과 이야기하고 있어요.", "유기농 농장의 주인이요.", "농업 협회에서요."], "ans": 1, "audio": "Test05_19.mp3"}, {"n": 20, "part": 2, "q": "The flavors in the main dish are a bit too strong.", "qko": "주요리의 양념이 조금 지나치게 강하네요.", "opts": ["I agree. They're not to my taste.", "These dishes must be rinsed off very well.", "When will you graduate from culinary school?"], "optko": ["저도 동의해요. 제 입맛에 맞지 않아요.", "이 접시들은 아주 잘 헹궈져야 해요.", "당신은 요리학교를 언제 졸업할 건가요?"], "ans": 0, "audio": "Test05_20.mp3"}, {"n": 21, "part": 2, "q": "When did you begin accepting applications for the analysis job?", "qko": "분석 직무를 위한 지원서를 언제부터 받기 시작했나요?", "opts": ["Through the newspaper review.", "Not long ago.", "An important research grant."], "optko": ["신문 논평을 통해서요.", "오래되지 않았어요.", "중요한 연구 보조금이요."], "ans": 1, "audio": "Test05_21.mp3"}, {"n": 22, "part": 2, "q": "This business plan summary turned out extremely well.", "qko": "이 사업 계획서의 개요는 아주 잘 되었어요.", "opts": ["Yes, it's very thorough.", "Why does it keep turning off?", "The planning committee is running late."], "optko": ["네, 그것은 매우 완벽해요.", "왜 그것이 계속 꺼지나요?", "기획 위원회가 늦어지네요."], "ans": 0, "audio": "Test05_22.mp3"}, {"n": 23, "part": 2, "q": "Why don't we have the staff outing at the end of May?", "qko": "5월 말에 직원 야유회를 하는 게 어때요?", "opts": ["We didn't take any time off.", "Have they handed them out yet?", "I think we should have it later."], "optko": ["우리는 휴가를 전혀 내지 않았어요.", "그들이 그것을 벌써 나눠줬나요?", "저는 우리가 그것을 나중에 하는 게 좋을 것 같아요."], "ans": 2, "audio": "Test05_23.mp3"}, {"n": 24, "part": 2, "q": "Hasn't the museum put up some additional displays?", "qko": "박물관이 추가 전시를 선보이지 않았나요?", "opts": ["I've never seen this play.", "This is a great exhibition.", "They're being set up at the moment."], "optko": ["저는 이 연극을 본 적이 없어요.", "이것은 대단한 전시회에요.", "그것들은 바로 지금 설치되고 있어요."], "ans": 2, "audio": "Test05_24.mp3"}, {"n": 25, "part": 2, "q": "The ferry departs from the pier at 5 P.M. precisely.", "qko": "여객선은 정확히 오후 5시에 부두에서 출발해요.", "opts": ["You'll have to ask the ticketing agent.", "That's only an hour from now.", "An announcement for passengers."], "optko": ["매표소 직원에게 물어보셔야 할 거예요.", "그건 지금부터 불과 한 시간 후네요.", "승객들을 위한 공지요."], "ans": 1, "audio": "Test05_25.mp3"}, {"n": 26, "part": 2, "q": "The benefit concert was quite impressive, wasn't it?", "qko": "그 자선 콘서트는 꽤 인상적이었어요, 그렇지 않았나요?", "opts": ["I'm looking forward to it also.", "It was well-organized.", "We are concerned about it too."], "optko": ["저도 그것을 기대하고 있어요.", "그것은 잘 구성되어 있었어요.", "저희도 그것에 대해 염려하고 있어요."], "ans": 1, "audio": "Test05_26.mp3"}, {"n": 27, "part": 2, "q": "Aren't there still people waiting to be interviewed?", "qko": "인터뷰를 하기 위해 기다리고 있는 사람들이 아직 있지 않나요?", "opts": ["There are two candidates in the lobby.", "A magazine writer interviewed us.", "I saw it on the news last night."], "optko": ["두 명의 지원자들이 로비에 있어요.", "잡지 기자가 우리를 인터뷰했어요.", "저는 그것을 어젯밤 뉴스에서 봤어요."], "ans": 0, "audio": "Test05_27.mp3"}, {"n": 28, "part": 2, "q": "Can I get you anything to eat or drink?", "qko": "먹을 것이나 마실 것을 가져다드릴까요?", "opts": ["On the back of the menu.", "Actually, I'll wait until my friend arrives.", "No, the lounge was very neat."], "optko": ["메뉴의 뒷면이요.", "사실, 저는 제 친구가 도착할 때까지 기다릴 거예요.", "아니요, 휴게실은 매우 깔끔했어요."], "ans": 1, "audio": "Test05_28.mp3"}, {"n": 29, "part": 2, "q": "Has the supply store's delivery van been repaired?", "qko": "물품 창고의 화물 운송 트럭이 수리되었나요?", "opts": ["Yes, and it is already being used again.", "It has lots of storage space.", "Well, delivery will cost extra."], "optko": ["네, 그리고 그것은 이미 다시 사용되고 있어요.", "그것은 많은 저장 공간을 가지고 있어요.", "글쎄요, 운송은 추가 비용이 들 거예요."], "ans": 0, "audio": "Test05_29.mp3"}, {"n": 30, "part": 2, "q": "We need to hire professionals to clean the windows.", "qko": "우리는 창문들을 닦기 위해 전문가들을 고용해야 해요.", "opts": ["They sent us a billing statement.", "Hang the sign a bit higher.", "I'll inquire about services."], "optko": ["그들이 우리에게 대금 청구서를 보냈어요.", "간판을 조금 더 높게 다세요.", "제가 서비스에 대해 문의할게요."], "ans": 2, "audio": "Test05_30.mp3"}, {"n": 31, "part": 2, "q": "Can you speak with Ms. Tanner, or should I call her?", "qko": "당신이 Ms. Tanner와 이야기할 수 있나요, 아니면 제가 그녀에게 전화를 걸어야 할까요?", "opts": ["I can't remember what it's called.", "I think I'll just send her an e-mail.", "The contract information is in this file."], "optko": ["저는 그것이 뭐라고 불리는지 기억이 안 나요.", "저는 그냥 그녀에게 이메일을 보낼 생각이에요.", "계약 정보는 이 파일 안에 있어요."], "ans": 1, "audio": "Test05_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test05_32-34.mp3", "qs": [{"n": 32, "q": "Where most likely is the conversation taking place?", "opts": ["At a resort hotel", "At a car repair shop", "At an automobile rental agency", "At a tour office"], "ans": 2, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 33, "q": "What does the man inquire about?", "opts": ["The availability of tickets", "The location of a facility", "Baggage storage space", "Expected drop-off times"], "ans": 2, "ko": "남자는 무엇에 관해 문의하는가?"}, {"n": 34, "q": "What does the woman ask the man to do?", "opts": ["Provide a form of identification", "Pay a percentage of a fee", "Describe his lost luggage", "Get his vehicle from a parking lot"], "ans": 0, "ko": "여자는 남자에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "M", "en": "Good morning. I don't have a reservation, but I would like to rent a car for a couple of days. Do you have anything available?", "ko": "안녕하세요. 저는 예약은 하지 않았지만, 이틀 정도 차 한 대를 빌리고 싶어요. 이용할 수 있는 게 있나요?"}, {"sp": "W", "en": "We do. What size car are you looking for?", "ko": "있습니다. 어떤 크기의 차를 찾고 계신가요?"}, {"sp": "M", "en": "Something spacious enough for four people. Also, is it possible to get a vehicle with a large trunk? We have quite a bit of luggage.", "ko": "네 명이 타기에 충분히 넓은 차요. 또, 큰 트렁크가 있는 차를 구하는 게 가능할까요? 저희가 짐이 좀 많아요."}, {"sp": "W", "en": "Of course. The CX2 sedan seats five people comfortably and has plenty of storage space. If you're interested in that vehicle, we can begin filling out the necessary paperwork. I'll just need to see your credit card and driver's license in order to proceed.", "ko": "물론이죠. CX2 세단은 다섯 명이 편하게 앉을 수 있고, 수납공간도 충분해요. 손님께서 그 차에 관심이 있으시다면, 필요한 서류 작성을 시작할 수 있어요. 진행하기 위해서 제가 손님의 신용 카드와 운전면허증만 보면 될 거예요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test05_35-37.mp3", "qs": [{"n": 35, "q": "What type of business most likely is Spectrum?", "opts": ["An art supply store", "A construction firm", "A painting company", "A moving service"], "ans": 2, "ko": "Spectrum사는 어떤 종류의 업체인 것 같은가?"}, {"n": 36, "q": "Why is the man calling?", "opts": ["To ask about a product", "To inquire about a charge", "To request a billing statement", "To confirm an order"], "ans": 1, "ko": "남자는 왜 전화를 하고 있는가?"}, {"n": 37, "q": "What does the man say he will do next?", "opts": ["Call an interior designer", "Send a payment", "Look at some paint samples", "Take some measurements"], "ans": 3, "ko": "남자는 다음에 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Spectrum Color Services. This is Danielle, what can I do for you today?", "ko": "Spectrum Color Services사입니다. 저는 Danielle입니다. 오늘 무엇을 도와드릴까요?"}, {"sp": "M", "en": "Hello, I was wondering if you could tell me how much you charge to paint a living room.", "ko": "안녕하세요, 거실을 페인트칠하는 데 얼마의 비용을 청구하는지 알려줄 수 있으신지 궁금해요."}, {"sp": "W", "en": "That would depend on the size of the room and the type of paint you choose. If you can give me that information, I could provide you with an estimate.", "ko": "그건 방의 크기와 선택하시는 페인트 종류에 달려있습니다. 저에게 그 정보를 주시면, 견적을 제공해드릴 수 있습니다."}, {"sp": "M", "en": "Well, I just want basic white paint, but I'm not certain about the size of the room. I'll go measure it right now and call you back in about 10 minutes.", "ko": "음, 저는 그냥 기본적인 흰색 페인트를 원하는데, 방의 크기는 정확히 모르겠네요. 지금 바로 가서 치수를 재보고 약 10분 후에 전화를 드리도록 할게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test05_38-40.mp3", "qs": [{"n": 38, "q": "Who most likely is the woman?", "opts": ["A shop owner", "A marketing specialist", "An event planner", "A jewelry designer"], "ans": 3, "ko": "여자는 누구인 것 같은가?"}, {"n": 39, "q": "Why does the woman say, \"the booth rental fee is $600\"?", "opts": ["To show interest in a proposal", "To provide a reason for a decision", "To correct an inaccurate statement", "To express uncertainty about a plan"], "ans": 3, "ko": "여자는 왜 \"부스 대여비가 600달러예요\"라고 말하는가?"}, {"n": 40, "q": "What does the man say about the expo?", "opts": ["It occurs in the same location annually.", "It has been rescheduled for a later date.", "It could improve the woman's business.", "It is sponsored by multiple companies."], "ans": 2, "ko": "남자는 박람회에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Tricia, these necklaces are very impressive. Do you plan to sell them at your friend's boutique like your other pieces?", "ko": "Tricia, 이 목걸이들이 참 인상적이네요. 당신의 다른 작품들처럼 그것들을 당신 친구의 부티크에서 판매할 계획인가요?"}, {"sp": "W", "en": "Yes. However, I feel as though my designs aren't getting enough attention. So, I'm considering sending in an application to attend this year's National Jewelry Expo to better advertise my work.", "ko": "네. 하지만, 저는 제 디자인이 충분히 주목을 받지 못하고 있는 것 같아요. 그래서, 저의 작품을 더 잘 홍보하기 위해 올해의 전국 보석 박람회에 참가하기 위한 신청서를 보낼까 생각 중이에요."}, {"sp": "M", "en": "That's a great idea. You could attract a lot of customers.", "ko": "그거 좋은 생각이네요. 당신은 많은 고객들을 끌어모을 수 있을 거예요."}, {"sp": "W", "en": "You think so? But, um . . . the booth rental fee is $600. That seems quite expensive.", "ko": "그렇게 생각하세요? 하지만, 음… 부스 대여비가 600달러예요. 꽤 비싼 것 같아요."}, {"sp": "M", "en": "Numerous people have used exposure from that event to help boost their businesses. I'm sure the same would happen for you.", "ko": "많은 사람들이 그 행사에서의 노출을 이용해서 그들의 사업을 신장시켰어요. 당신에게도 같은 결과가 있을 거라 확신해요."}, {"sp": "W", "en": "You're right . . . I'm gonna download the application form now and fill it out.", "ko": "당신 말이 맞아요… 지금 신청서를 내려받아서 작성하겠어요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test05_41-43.mp3", "qs": [{"n": 41, "q": "What did the man recently do?", "opts": ["Traveled to Seattle", "Helped to organize a sale", "Requested another assignment", "Cooperated with a marketing team"], "ans": 3, "ko": "남자는 최근에 무엇을 했는가?"}, {"n": 42, "q": "What problem does the woman mention?", "opts": ["A promotion has to be canceled.", "An incorrect branch was included.", "A program is not properly loading.", "A report was never turned in."], "ans": 1, "ko": "여자는 어떤 문제를 언급하는가?"}, {"n": 43, "q": "What does the man say he will do?", "opts": ["Revise some material", "Meet with a supervisor", "Update his work schedule", "Design a Web site"], "ans": 0, "ko": "남자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "I'd like to discuss a recent assignment that you collaborated with the marketing team on.", "ko": "저는 당신이 마케팅팀과 함께 공동으로 작업한 최근의 업무에 대해 논의하고 싶어요."}, {"sp": "M", "en": "No problem. Is there something specific you'd like to discuss?", "ko": "그럼요. 구체적으로 논의하고 싶은 게 있나요?"}, {"sp": "W", "en": "Yes, there is. You included an incorrect location in this online advertisement. It states that there will be a sale at our Seattle branch on July 22. However, the sale is actually going to be at our Portland branch.", "ko": "네, 있어요. 당신은 이 온라인 광고에 잘못된 장소를 포함시키셨어요. 광고는 7월 22일에 우리 시애틀 지점에서 할인 판매가 있을 거라고 알려주고 있어요. 하지만, 할인 판매는 실제로 우리의 포틀랜드 지점에서 있을 거예요."}, {"sp": "M", "en": "Really? I'm so sorry about that! I must have missed that while proofreading the advertisement. I will make the necessary changes to the advertisement immediately.", "ko": "정말요? 정말 죄송해요! 광고를 교정보는 중에 그것을 놓친 게 틀림없어요. 제가 바로 광고에 필요한 수정을 할게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음 → 미국식 발음", "audio": "Test05_44-46.mp3", "qs": [{"n": 44, "q": "Why did the man arrive early?", "opts": ["To assemble store shelves", "To repair some consoles", "To unpack some merchandise", "To send a shipment"], "ans": 2, "ko": "남자는 왜 일찍 도착했는가?"}, {"n": 45, "q": "Why should the speakers finish a task now?", "opts": ["Trucks need to be loaded.", "Customers are waiting at an entrance.", "A manager has given more assignments.", "A sales event has already begun."], "ans": 1, "ko": "화자들은 왜 지금 업무를 끝내야 하는가?"}, {"n": 46, "q": "What does the man suggest?", "opts": ["Clearing out a storage room", "Requesting additional assistance", "Asking shoppers to return later", "Delaying the store opening"], "ans": 1, "ko": "남자는 무엇을 제안하는가?"}], "script": [{"sp": "W1", "en": "Hey, Randy. Doesn't your shift start at 9 o'clock?", "ko": "안녕하세요, Randy. 당신의 근무는 9시에 시작하지 않나요?"}, {"sp": "M", "en": "Yeah, I came in early this morning to unpack the Digi 5 game consoles. They just arrived, and we need to get them on the shelves.", "ko": "네, Digi 5 게임기들의 포장을 풀기 위해 오늘 아침 일찍 왔어요. 게임기들이 방금 도착해서, 우리는 그것들을 선반에 진열해야 해요."}, {"sp": "W1", "en": "I see. Here . . . I'll help.", "ko": "그렇군요. 자… 제가 도와드릴게요."}, {"sp": "W2", "en": "Sorry to interrupt. I know we don't open for five more minutes, but some customers have already started to form a line at the door. They're here for the Digi 5.", "ko": "끼어들어서 미안해요. 우리가 문을 열려면 5분이 더 남았다는 것은 알지만, 몇몇 고객들이 벌써 입구에 줄을 서기 시작했어요. 그들은 Digi 5를 사려고 왔어요."}, {"sp": "W1", "en": "I was going to keep stocking the shelves after we opened, but we'd better finish soon if people are lined up.", "ko": "문을 열고 난 후에 계속해서 선반을 채우려고 했는데, 사람들이 줄을 서 있다면 빨리 끝내는 게 좋겠네요."}, {"sp": "M", "en": "Maybe one of us should ask Richard to give us a hand.", "ko": "우리 중 한 명이 Richard에게 도와달라고 요청하는 게 좋겠어요."}, {"sp": "W2", "en": "I can do that.", "ko": "제가 할게요."}, {"sp": "M", "en": "Thanks. He should be in the storeroom.", "ko": "감사해요. 그는 창고에 있을 거예요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test05_47-49.mp3", "qs": [{"n": 47, "q": "What problem does the woman mention?", "opts": ["A branch is currently understaffed.", "A theater requires new equipment.", "A film release has been postponed.", "A staff member missed a shift."], "ans": 0, "ko": "여자는 어떤 문제를 언급하는가?"}, {"n": 48, "q": "What does the man mean when he says, \"This is the busiest time of the year\"?", "opts": ["He needs to check a schedule.", "He agrees with a recommendation.", "He wants to promote a service.", "He has completed a task."], "ans": 1, "ko": "남자는 \"지금이 연중 가장 바쁜 시기잖아요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 49, "q": "What will probably happen later today?", "opts": ["Some interviews will be held.", "A Web site will be officially launched.", "Some employees will undergo training.", "A posting will be posted."], "ans": 3, "ko": "오늘 늦게 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "W", "en": "Colson, the Winchester branch of our cinema will need more personnel for the summer. Maybe we should hire three additional employees for the evening and weekend shifts.", "ko": "Colson, 여름 시즌을 위해서 우리 영화관의 Winchester 지점에 직원들이 더 필요할 거예요. 아마도 우리는 저녁과 주말 교대 근무를 위해 세 명의 추가 직원을 고용해야 해요."}, {"sp": "M", "en": "Yeah . . . This is the busiest time of the year. Could you make a job posting? Just include a brief description of the position and list our required qualifications.", "ko": "네… 지금이 연중 가장 바쁜 시기잖아요. 당신이 채용 공고를 작성해 주시겠어요? 간단한 직무 설명을 포함시키고 요구되는 자격들을 나열해 주세요."}, {"sp": "W", "en": "Sure. I'll try to finish it before I break for lunch.", "ko": "물론이죠. 점심 먹기 전에 그것을 끝내도록 노력해 볼게요."}, {"sp": "M", "en": "That'd be ideal. I'll review it when you are finished, and then add it to our company Web site later this afternoon.", "ko": "그게 가장 좋겠네요. 당신이 그것을 끝내면 제가 검토해보고, 오늘 오후 늦게 우리 회사 웹사이트에 추가할게요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test05_50-52.mp3", "qs": [{"n": 50, "q": "What is the purpose of the call?", "opts": ["To apply for membership", "To reserve accommodations", "To book some tickets", "To ask about transportation costs"], "ans": 2, "ko": "전화의 목적은 무엇인가?"}, {"n": 51, "q": "What is the man concerned about?", "opts": ["Guide availability", "Program duration", "A starting time", "A tour price"], "ans": 3, "ko": "남자는 무엇에 대해서 걱정하는가?"}, {"n": 52, "q": "How can visitors receive a discount?", "opts": ["By paying in advance", "By showing up early", "By being a cardholder", "By getting a family pass"], "ans": 2, "ko": "방문객들은 어떻게 할인을 받을 수 있는가?"}], "script": [{"sp": "M", "en": "Hello, I'm calling to reserve three tickets for the Wild Animals guided tour at Jungle Wonderland this coming Saturday. How much will that cost?", "ko": "안녕하세요, 다가오는 토요일에 있을 Jungle Wonderland의 야생 동물 안내 투어에 표 세 장을 예약하기 위해 전화드립니다. 비용은 얼마나 들까요?"}, {"sp": "W", "en": "It's $40 per person. The tour begins at 9 A.M. and will last two and a half hours.", "ko": "1인당 40달러입니다. 투어는 오전 9시에 시작되고 2시간 30분간 진행될 것입니다."}, {"sp": "M", "en": "Hmm . . . That's higher than I had expected. Have your rates changed recently? My friend went on the same tour last month, and she said it cost $32 per person.", "ko": "흠… 그건 제가 예상했던 것보다 더 비싸네요. 최근에 요금이 바뀌었나요? 제 친구가 지난달에 같은 투어를 갔는데, 1인당 32달러가 들었다고 말했어요."}, {"sp": "W", "en": "She must have our Jungle Wonderland Annual Pass Card. Cardholders automatically receive a 20 percent discount on admission and tours in the wildlife preserve for a year.", "ko": "그분은 저희 Jungle Wonderland 연간 입장 카드를 가지고 계실 겁니다. 카드 소지자들은 자동으로 1년 동안 야생 동물 보호 구역의 입장과 투어에 대해 20퍼센트 할인을 받게 되거든요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test05_53-55.mp3", "qs": [{"n": 53, "q": "What did the man do several hours ago?", "opts": ["Met a recording artist", "Signed some paperwork", "Agreed to a deal", "Viewed a rental unit"], "ans": 3, "ko": "남자는 몇 시간 전에 무엇을 했는가?"}, {"n": 54, "q": "Who is Janet Davidson?", "opts": ["A professional photographer", "A building owner", "A real estate agent", "An office secretary"], "ans": 1, "ko": "Janet Davidson은 누구인가?"}, {"n": 55, "q": "What does the woman ask the man to do?", "opts": ["Make an appointment", "Update a schedule", "Confirm a layout", "Pay a deposit"], "ans": 0, "ko": "여자는 남자에게 무엇을 하도록 요청하는가?"}], "script": [{"sp": "M", "en": "Erin, I met up with our realtor a few hours ago. He showed me a vacant space that would be perfect for our recording studio.", "ko": "Erin, 저는 몇 시간 전에 우리 부동산 중개인과 만났어요. 그가 저에게 우리의 녹음실에 안성맞춤일 빈 장소를 보여주었어요."}, {"sp": "W", "en": "Was the unit in a building on Ferguson Avenue? If so, I received an e-mail from him about the vacancy last night.", "ko": "그곳이 Ferguson가에 있는 건물에 있었나요? 만일 그렇다면, 제가 어젯밤에 그로부터 그 장소에 관한 이메일을 받았어요."}, {"sp": "M", "en": "Yes, that's the one. The space has a very practical layout. Plus, there is enough room for a reception area and a private office. I was even introduced to the owner of the building, Janet Davidson. She was quite welcoming and professional.", "ko": "네, 바로 그거예요. 그 장소는 배치가 매우 실용적이에요. 게다가, 접수처와 개인 사무실을 위한 충분한 공간이 있어요. 저는 그 건물의 주인인 Janet Davidson도 소개받았어요. 그녀는 상당히 따뜻하고 전문적이었어요."}, {"sp": "W", "en": "That sounds promising. Would you arrange another showing for tomorrow? I'd like to see the property too.", "ko": "조짐이 좋은 것 같네요. 내일 한 번 더 볼 수 있도록 주선해 주시겠어요? 저도 그 건물이 보고 싶어요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test05_56-58.mp3", "qs": [{"n": 56, "q": "What are the speakers mainly discussing?", "opts": ["A change to a safety regulation", "Preparations for an activity", "An itinerary for a trip", "Complications with a vessel"], "ans": 1, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 57, "q": "What does the woman mention about Splash World?", "opts": ["It extended operational hours.", "It is currently closed.", "It is located nearby.", "It restocked some goods."], "ans": 2, "ko": "여자는 Splash World에 관해 무엇을 언급하는가?"}, {"n": 58, "q": "What does the man ask about?", "opts": ["A group's departure time", "A supplier's branch location", "A product's model number", "A business's contact information"], "ans": 3, "ko": "남자는 무엇에 관해 문의하는가?"}], "script": [{"sp": "M", "en": "Have you loaded the scuba gear into the boat yet? We need enough equipment to take 10 people on a diving trip.", "ko": "배에 스쿠버 장비를 벌써 실었나요? 우리는 다이빙 관광에 열 명을 데려가기에 충분한 장비가 필요해요."}, {"sp": "W", "en": "Yeah, but I discovered a crack in one of the masks.", "ko": "네, 하지만 마스크들 중 하나에서 금이 간 것을 발견했어요."}, {"sp": "M", "en": "Really? That's a problem since the other dive group has taken all the spare ones with them.", "ko": "정말요? 다른 다이빙 그룹이 여분의 마스크들을 전부 가져가서 그게 문제네요."}, {"sp": "W", "en": "Hmm . . . Splash World, the dive supply shop, is really close to here. If they have any in stock, I can go pick one up. Why don't you give them a call and see if they have what we need?", "ko": "흠… 다이빙용품 가게인 Splash World가 여기서 매우 가까워요. 만약 그들에게 재고가 있다면, 제가 가서 하나 사올 수 있어요. 거기에 전화해서 우리가 필요한 게 있는지 확인하는 게 어때요?"}, {"sp": "M", "en": "Good idea! I'll get right on that. Only . . . do you know the store's phone number?", "ko": "좋은 생각이에요! 지금 바로 그것을 처리할게요. 다만… 그 가게의 전화번호를 아나요?"}, {"sp": "W", "en": "No, but I bet Reggie does.", "ko": "아니요, 하지만 Reggie는 분명히 알 거예요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음 → 영국식 발음", "audio": "Test05_59-61.mp3", "qs": [{"n": 59, "q": "What does the man want to do?", "opts": ["Change his phone number", "Exchange a computer", "Buy a mobile device", "Upgrade a cellular plan"], "ans": 2, "ko": "남자는 무엇을 하고 싶어 하는가?"}, {"n": 60, "q": "What aspect of the PlusTouch 50 is the man interested in?", "opts": ["Its processing speed", "Its design", "Its various accessories", "Its price"], "ans": 3, "ko": "남자는 PlusTouch 50의 어떤 면에 관심이 있는가?"}, {"n": 61, "q": "What is mentioned about Graystone Electronics?", "opts": ["It opened a new branch last month.", "It merged with another company.", "It is offering products at a discount.", "It is closed on the weekends."], "ans": 2, "ko": "Graystone Electronics에 관해 무엇이 언급되는가?"}], "script": [{"sp": "M", "en": "I think I'm ready for a new cell phone. Do either of you have any recommendations?", "ko": "전 새로운 휴대 전화를 살 준비가 된 것 같아요. 두 분 중 누구라도 추천할 게 있으신가요?"}, {"sp": "W1", "en": "My phone has worked out great—the ShockPhone 20. It's fast, and it has a modern design.", "ko": "제 휴대 전화 ShockPhone 20은 잘 작동해 왔어요. 그것은 빠르고, 최신 디자인이에요."}, {"sp": "M", "en": "I've heard that model's great, but it's out of my budget.", "ko": "그 모델이 좋다고 들었지만, 제 예산 밖이에요."}, {"sp": "W2", "en": "Mine's a PlusTouch 50. It's pretty basic, but it's only $300.", "ko": "제 것은 PlusTouch 50이에요. 꽤 기본적이지만, 300달러밖에 안 해요."}, {"sp": "M", "en": "The less expensive one sounds better. I'll purchase one at Harbor Cellular this weekend.", "ko": "덜 비싼 것이 더 좋을 것 같네요. 이번 주말에 Harbor Cellular에서 하나 사야겠어요."}, {"sp": "W1", "en": "I heard that store is closed for renovations this month.", "ko": "그 가게는 이번 달에 수리 때문에 문을 닫는다고 들었어요."}, {"sp": "W2", "en": "Looks like you'll have to go to Graystone Electronics instead. Fortunately, it's having a sale.", "ko": "대신 Graystone Electronics에 가셔야 할 것 같아요. 운 좋게도, 그곳은 할인 판매를 하고 있어요."}, {"sp": "M", "en": "Thanks for the information. I wasn't aware about Harbor's closing.", "ko": "알려줘서 고마워요. 저는 Harbor가 문을 닫는 것에 대해 알지 못했어요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test05_62-64.mp3", "qs": [{"n": 62, "q": "What did the woman leave in her vehicle?", "opts": ["An admission pass", "A camera", "A container of sunscreen", "A bottle of water"], "ans": 1, "ko": "여자는 그녀의 차에 무엇을 두고 왔는가?"}, {"n": 63, "q": "Look at the graphic. Where will the speakers meet?", "opts": ["In Zone 1", "In Zone 2", "In Zone 3", "In Zone 4"], "ans": 0, "ko": "시각 자료를 보시오. 화자들은 어디에서 만날 것인가?"}, {"n": 64, "q": "What does the man say he will do?", "opts": ["Read through a brochure", "Change into his swimming trunks", "Request some schedule information", "Look for some keys"], "ans": 2, "ko": "남자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Hold on, Craig. I need to head back to the car before entering the park.", "ko": "잠시만요, Craig. 유원지에 들어가기 전에 저는 차로 다시 가야 해요."}, {"sp": "M", "en": "What for?", "ko": "무엇 때문에요?"}, {"sp": "W", "en": "I just realized that I left my camera in my car. I definitely want to have that on me today.", "ko": "제 카메라를 차 안에 두고 온 것이 방금 생각났어요. 저는 오늘 꼭 그걸 가지고 다니고 싶어요."}, {"sp": "M", "en": "OK, but I'd rather not walk all the way to our parking spot. It's on the far end of the lot.", "ko": "알겠어요, 하지만 우리가 주차한 곳까지 내내 걷고 싶지 않아요. 주차장 끝에 있잖아요."}, {"sp": "W", "en": "Well, we've already purchased our tickets, so why don't I just meet you inside?", "ko": "음, 우리는 이미 표를 구매했으니까, 제가 당신을 안에서 만나는 것이 어때요?"}, {"sp": "M", "en": "Yeah, that's fine. After you enter the park, go to Rollercoaster Mountain. It's right next to Water World. And I'll stop by the visitor center on my way to find out what time the parade begins today.", "ko": "네, 좋아요. 유원지에 들어와서, 롤러코스터 산으로 가세요. 이것은 워터 월드 바로 옆에 있어요. 그리고 저는 가는 길에 오늘 퍼레이드가 몇 시에 시작하는지 알아보기 위해 방문자 센터에 들를게요."}], "gimg": "hk2_t5_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test05_65-67.mp3", "qs": [{"n": 65, "q": "What did the woman already do?", "opts": ["Canceled an appointment", "Went to a different floor", "Spoke to another receptionist", "Updated some information"], "ans": 1, "ko": "여자는 이미 무엇을 했는가?"}, {"n": 66, "q": "Why did Mr. Pinkerton move into a new office?", "opts": ["He began a special marketing project.", "He required a larger workspace.", "He received a promotion.", "He joined another department."], "ans": 3, "ko": "Mr. Pinkerton은 왜 새로운 사무실로 옮겼는가?"}, {"n": 67, "q": "Look at the graphic. Which office will the woman head to?", "opts": ["101", "102", "201", "202"], "ans": 1, "ko": "시각 자료를 보시오. 여자는 어느 사무실로 갈 것인가?"}], "script": [{"sp": "W", "en": "Excuse me. I'm scheduled to meet with Harvey Pinkerton. However, the office listed for him on the directory here in the lobby is incorrect. I went up to the second floor, but someone else was using that office.", "ko": "실례합니다. 저는 Harvey Pinkerton과 만나기로 예정되어 있어요. 그런데, 여기 로비에 있는 건물 안내판에 그의 사무실이라고 나와 있는 곳이 틀려요. 제가 2층에 올라가 봤는데, 그 사무실을 다른 사람이 사용하고 있었어요."}, {"sp": "M", "en": "Oh, I'm very sorry for the inconvenience. Mr. Pinkerton was recently transferred from marketing to sales, so he moved to another floor.", "ko": "아, 불편을 드려 정말 죄송합니다. Mr. Pinkerton은 최근에 마케팅 부서에서 영업 부서로 이동해서, 다른 층으로 옮겼습니다."}, {"sp": "W", "en": "I see . . . Well, where is his new office?", "ko": "그렇군요… 음, 그의 새로운 사무실은 어디인가요?"}, {"sp": "M", "en": "He's in Mr. Olsen's old office, which is down the hall and to the right.", "ko": "그는 Mr. Olsen의 이전 사무실에 있는데, 그곳은 복도를 따라가서 오른편에 있어요."}, {"sp": "W", "en": "OK, I'll head there now. Thanks.", "ko": "알겠어요, 지금 거기로 갈게요. 감사해요."}], "gimg": "hk2_t5_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test05_68-70.mp3", "qs": [{"n": 68, "q": "Who most likely is the woman?", "opts": ["A financial consultant", "An engineer", "An architect", "A Web designer"], "ans": 3, "ko": "여자는 누구인 것 같은가?"}, {"n": 69, "q": "Look at the graphic. Which office will the woman use?", "opts": ["Office 1", "Office 2", "Office 3", "Office 4"], "ans": 2, "ko": "시각 자료를 보시오. 여자는 어느 사무실을 사용할 것인가?"}, {"n": 70, "q": "What will the woman probably do next?", "opts": ["Go on a building tour", "Meet with a manager", "Participate in an orientation", "Introduce herself to coworkers"], "ans": 0, "ko": "여자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "I'm very happy to have you join our engineering firm, Ms. Doyle. You have a lot of experience designing Web sites, so I'm sure you will play an important role in our upcoming projects.", "ko": "당신이 우리 엔지니어링 회사에 합류하시게 되어 정말 기뻐요, Ms. Doyle. 당신은 웹사이트를 디자인하는 데 많은 경험이 있어서, 저는 당신이 우리의 다가오는 프로젝트에서 중요한 역할을 하실 거라고 확신해요."}, {"sp": "W", "en": "Well, I very much look forward to working here too.", "ko": "음, 저도 이곳에서 일하는 것이 정말 많이 기대돼요."}, {"sp": "M", "en": "Regarding your new office, we currently have four available spaces that you can choose from. Do you have any particular requirements for your workspace?", "ko": "당신의 새로운 사무실과 관련해서, 저희에겐 현재 당신이 선택하실 수 있는 이용 가능한 공간이 네 군데 있어요. 작업 공간에 대해 특정한 요건이 있으신가요?"}, {"sp": "W", "en": "Well, I plan to hold regular meetings in my office with my team, so the bigger the better . . . Plus, a window would be nice.", "ko": "음, 저는 제 사무실에서 제 팀과 정기 회의를 할 계획이라서, 클수록 더 좋아요. 게다가, 창문이 있었으면 좋겠네요."}, {"sp": "M", "en": "We have one that should meet your needs. You can move your things in after I show you around our headquarters.", "ko": "당신의 요구를 만족시킬 만한 곳이 한 군데 있어요. 제가 우리 본사를 안내해드린 다음에 당신의 짐을 옮기시면 되겠어요."}], "gimg": "hk2_t5_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test05_71-73.mp3", "qs": [{"n": 71, "q": "Who is Wan Cheol Shin?", "opts": ["A musical performer", "A famous actor", "A symphony conductor", "A guest speaker"], "ans": 0, "ko": "Wan Cheol Shin은 누구인가?"}, {"n": 72, "q": "What will be available at the event?", "opts": ["Free brochures", "Refreshments", "Music recordings", "Signed posters"], "ans": 2, "ko": "행사에서 무엇을 구할 수 있을 것인가?"}, {"n": 73, "q": "Why would listeners call the provided telephone number?", "opts": ["To check performance times", "To inquire about tickets", "To learn about an artist", "To purchase a CD"], "ans": 1, "ko": "청자들은 왜 제공된 전화번호로 전화할 것인가?"}], "script": [{"sp": "M", "en": "Join us at the Suarez Performing Arts Center for a one-evening performance by world-renowned violinist Wan Cheol Shin. Mr. Shin will perform an evening of classical pieces and modern works accompanied by the San Bernardo Symphony Orchestra. Recordings of Mr. Shin's music will be available for purchase after the concert. Doors for the concert open at 7:20 P.M. tomorrow, April 9. For tickets and reservations, please call the box office at 555-7219. Don't miss out on your chance to see Wan Cheol Shin performing live. Make your reservations today!", "ko": "세계적으로 유명한 바이올리니스트인 Wan Cheol Shin의 일일 저녁 공연을 위해 Suarez 공연 예술 센터에서 저희와 함께하십시오. Mr. Shin은 San Bernardo 교향악단의 반주를 받아 고전곡과 현대곡들로 이루어진 저녁 공연을 할 것입니다. Mr. Shin의 음반은 연주회가 끝난 뒤 구매 가능할 것입니다. 연주회장의 문은 내일 4월 9일 저녁 7시 20분에 엽니다. 표와 예매에 대해서는, 555-7219로 매표소에 전화주십시오. Wan Cheol Shin이 라이브로 공연하는 모습을 볼 기회를 놓치지 마십시오. 오늘 예매하세요!"}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test05_74-76.mp3", "qs": [{"n": 74, "q": "Where does the talk most likely take place?", "opts": ["At a job orientation", "At a product launch", "At a trade fair", "At a fashion seminar"], "ans": 3, "ko": "담화는 어디에서 일어나는 것 같은가?"}, {"n": 75, "q": "What were given to the listeners?", "opts": ["Event programs", "Performance reports", "Personal name tags", "Fabric samples"], "ans": 0, "ko": "청자들에게 무엇이 주어졌는가?"}, {"n": 76, "q": "What will the participants do in the afternoon?", "opts": ["Look at new apparel", "Watch a presentation", "Take part in group activities", "Review some documents"], "ans": 1, "ko": "참가자들은 오후에 무엇을 할 것인가?"}], "script": [{"sp": "W", "en": "Good morning, and welcome to this seminar on European clothing trends. I will be your lecturer today. My name is Caroline LeGrand, and I head the design department at Tyler Sharp Apparel. I'm delighted to see such a large turnout here today, as I will be discussing a very interesting topic that affects everyone within the fashion industry. All of you were handed a copy of today's program, which outlines everything that will take place. The lecture should last about two hours and take us right into lunch at noon. Then, the afternoon session will get underway at 1 o'clock. For that segment, another fashion designer, Liv Holbein, will give a slide show presentation. OK, now let's begin.", "ko": "안녕하십니까, 유럽 의류 동향에 관한 이번 세미나에 오신 걸 환영합니다. 저는 오늘 여러분의 강사입니다. 제 이름은 Caroline LeGrand이고, Tyler Sharp 의류 회사에서 디자인 부서를 이끌고 있습니다. 저는 패션 산업 내에 있는 모든 사람들에게 영향을 주는 매우 흥미로운 주제에 대해 논할 것이기 때문에, 오늘 이곳에서 이렇게 많은 참가자를 보게 되어 기쁩니다. 여러분 모두 오늘의 일정을 한 부 받으셨는데, 이는 오늘 있을 모든 것의 개요를 보여줍니다. 강의는 약 2시간 동안 지속될 것이고 정오에 곧바로 점심 식사를 하게 될 것입니다. 그러고 나서, 1시에 오후 활동이 시작되겠습니다. 그 부분 동안에는, 또 한 명의 패션 디자이너인 Liv Holbein께서 슬라이드 쇼 발표를 해주실 것입니다. 자, 이제 시작합시다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test05_77-79.mp3", "qs": [{"n": 77, "q": "What is the announcement mainly about?", "opts": ["A scientific discovery", "A facility reopening", "The results of a survey", "The release of a publication"], "ans": 1, "ko": "공지는 주로 무엇에 관한 것인가?"}, {"n": 78, "q": "According to the speaker, what topic did a recent study cover?", "opts": ["Educational approaches", "Touchscreen technology", "Star development", "Environmental damage"], "ans": 2, "ko": "화자에 따르면, 최근 연구는 어떤 주제를 다루었는가?"}, {"n": 79, "q": "Why does the speaker say, \"Mr. Donner is just finishing up some preparations\"?", "opts": ["To encourage people to take a seat", "To explain a brief delay", "To apologize for a staffing shortage", "To express excitement about an exhibit"], "ans": 1, "ko": "화자는 왜 \"Mr. Donner는 준비를 막 끝내는 중입니다\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Hello, everyone. This morning marks the first time the Norfield Planetarium has been accessible to the public following renovations and improvements. Upon entering the building, you'll be pleased to see that the majority of its sections have been completely redone. Our main exhibit hall, for instance, now features a variety of educational displays that you can interact with through touchscreen technology. To commemorate this special day, astronomer and local professor Shane Donner is going to talk a bit about the findings from his recent study on star formation. Although the talk was supposed to begin five minutes ago, Mr. Donner is just finishing up some preparations. So, you all are free to check out the exhibit across the hall until further notice.", "ko": "안녕하세요, 여러분. 오늘 아침은 Norfield 천문관이 수리와 개선 이후에 대중에 처음으로 공개된 것을 기념하는 날입니다. 건물에 들어가시자마자, 대부분의 구역이 완전하게 다시 꾸며진 것을 보면 기쁘실 것입니다. 예를 들어, 저희의 주 전시관은, 이제 여러분이 터치스크린 기술을 통해 상호 작용할 수 있는 다양한 교육적인 전시들을 특별히 포함합니다. 이 특별한 날을 기념하기 위해, 천문학자이자 지역 교수인 Shane Donner가 별의 형성에 관한 그의 최근 연구의 결과에 대해 약간 이야기할 것입니다. 비록 이야기는 5분 전에 시작하기로 했었지만, Mr. Donner는 준비를 막 끝내는 중입니다. 자, 여러분 모두 이 후의 공지가 있을 때까지 홀 건너편의 전시를 확인하실 수 있습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test05_80-82.mp3", "qs": [{"n": 80, "q": "What did a technician do this morning?", "opts": ["Installed some machinery", "Inspected a device", "Updated some software", "Relocated some supplies"], "ans": 1, "ko": "기술자는 오늘 아침에 무엇을 했는가?"}, {"n": 81, "q": "Why does the speaker say, \"a delivery will be made this week\"?", "opts": ["To make a correction", "To show surprise", "To offer assurance", "To confirm some speculation"], "ans": 2, "ko": "화자는 왜 \"배송은 이번 주에 이루어질 것입니다\"라고 말하는가?"}, {"n": 82, "q": "What does the speaker suggest doing?", "opts": ["Waiting for a specialist", "Speaking with a team manager", "Adjusting a work schedule", "Using another machine"], "ans": 3, "ko": "화자는 무엇을 할 것을 제안하는가?"}], "script": [{"sp": "M", "en": "I have a quick announcement. After receiving a few complaints, I had a technician look at our old shredder this morning. It appears that there is a serious problem with its cutting blades, and it has effectively stopped working. I know this is a major inconvenience for you all. However, I've contacted Mellor Supplies, and a delivery will be made this week. If you need to shred anything in the meantime, just use the one in the accounting department's office on the third floor. Staff there have been notified that some of you may make use of the machine. All right, that's all for now.", "ko": "간단한 공지를 하겠습니다. 몇몇 불만이 접수된 후, 저는 오늘 아침에 기술자가 저희의 오래된 파쇄기를 살펴보도록 하였습니다. 절단 날에 심각한 문제가 있는 것으로 보입니다. 그것은 실질적으로 작동을 멈추었습니다. 이것이 여러분 모두에게 심각한 불편 사항이라는 것을 압니다. 하지만, 제가 Mellor Supplies사에 연락했고, 배송은 이번 주에 이루어질 것입니다. 만약 그동안 무언가를 파쇄해야 한다면, 3층 회계부 사무실에 있는 것을 사용하세요. 그곳 직원들은 여러분 중 일부가 그 기계를 사용할 수도 있다는 것을 통지받았습니다. 좋습니다, 이상입니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test05_83-85.mp3", "qs": [{"n": 83, "q": "Who most likely is the speaker?", "opts": ["A personal assistant", "A program manager", "A park caretaker", "A city administrator"], "ans": 3, "ko": "화자는 누구인 것 같은가?"}, {"n": 84, "q": "According to the speaker, what does the listener want to do?", "opts": ["Volunteer at an outing", "Arrange a tour", "Make a booking", "Join a civic organization"], "ans": 2, "ko": "화자에 따르면, 청자는 무엇을 하고 싶어 하는가?"}, {"n": 85, "q": "Why might the listener visit a Web site?", "opts": ["To pay a deposit", "To view some images", "To upload a review", "To check for updates"], "ans": 1, "ko": "청자는 왜 웹사이트를 방문할 수도 있는가?"}], "script": [{"sp": "M", "en": "Hello. This is Tyrone Dyson calling from the city of Dallas's Department of Parks and Recreation. I received your message yesterday about possibly reserving the main room at the Pointer Park Community Center for a gathering on Saturday, September 2. Unfortunately, another group has already booked the space for that specific date you requested. However, I've contacted Dallas's other community center near Gleeson Park and was informed that they do have a space available at that time. If you are interested in booking that room, let me know. You can check out details and photos of the space by visiting www.dallasrecreation.gov. Thanks, and have a great day.", "ko": "안녕하세요. 저는 댈러스시의 공원 및 여가시설 관리부에서 전화드리는 Tyrone Dyson입니다. 저는 어제 9월 2일 토요일의 모임을 위해 Pointer 공원 시민 문화 회관에 큰 방을 예약하는 것이 가능한지에 관한 귀하의 메시지를 받았습니다. 안타깝게도, 다른 단체가 귀하께서 요청하신 그 특정 날짜에 그 공간을 이미 예약했습니다. 하지만, 제가 Gleeson 공원 근처에 있는 댈러스의 다른 시민 문화 회관에 연락하였고 그 시간에 이용 가능한 공간이 있다는 것을 통지받았습니다. 그 방을 예약하는 것에 관심이 있으시다면, 저에게 알려주십시오. www.dallasrecreation.gov를 방문하여 이 공간의 세부 사항과 사진들을 확인하실 수 있습니다. 감사드리며, 좋은 하루 보내십시오."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test05_86-88.mp3", "qs": [{"n": 86, "q": "What most likely do the listeners do for work?", "opts": ["Provide technical support", "Develop new software programs", "Consult companies", "Sell products over the phone"], "ans": 3, "ko": "청자들은 어떤 일을 하는 것 같은가?"}, {"n": 87, "q": "According to the speaker, why are communication skills important?", "opts": ["They make it easier to find new customers.", "They increase the likelihood of being hired.", "They allow customers to feel assured.", "They motivate other employees."], "ans": 2, "ko": "화자에 따르면, 의사소통 능력이 왜 중요한가?"}, {"n": 88, "q": "What does the speaker ask listeners to do?", "opts": ["Provide feedback", "Contact some clients", "Watch a short video", "Participate in exercises"], "ans": 3, "ko": "화자는 청자들에게 무엇을 하라고 요청하는가?"}], "script": [{"sp": "M", "en": "My name is Samir Nasser, and I'm a consultant and motivational speaker. I've been invited here by your employer to speak about how developing strong communication skills can improve your work life. As telemarketers for a software company, your ability to communicate with customers is obviously an essential part of your job. It enables you to express your thoughts clearly and concisely, which will in turn improve clients' confidence in you. But communication skills are not only important when it comes to increasing sales. They're also crucial for fostering healthy work relationships. In fact, the number one cause of workplace conflict is poor communication. To help prevent such issues, I'd like us all to participate in some activities together aimed at strengthening interactions between colleagues.", "ko": "제 이름은 Samir Nasser이며, 저는 상담가이자 동기부여 연설가입니다. 저는 뛰어난 의사소통 능력을 발전시키는 것이 여러분의 직장 생활을 어떻게 개선할 수 있는지에 대해 말씀드리기 위해 여러분의 고용주로부터 이곳으로 초대받았습니다. 소프트웨어 회사의 텔레마케터로서, 고객들과 소통하는 능력은 여러분의 직업에서 분명히 필수적인 부분입니다. 그것은 여러분이 여러분의 생각을 명확하고 간결하게 표현하는 것을 가능하게 하는데, 이는 결과적으로 여러분에 대한 고객들의 신뢰를 향상시킬 것입니다. 하지만 의사소통 능력은 판매 증가에 있어서만 중요한 것이 아닙니다. 그것들은 또한 건강한 직장 내 관계를 조성하는 데 결정적입니다. 사실, 직장 갈등의 가장 큰 원인은 서툰 의사소통입니다. 이러한 문제를 막기 위해, 저는 우리 모두 함께 직장 동료 간 소통 강화를 목표로 한 활동에 참여했으면 합니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test05_89-91.mp3", "qs": [{"n": 89, "q": "What is the main topic of the news report?", "opts": ["An upcoming election", "A selected award recipient", "A medical facility", "A construction project"], "ans": 1, "ko": "뉴스 보도의 주제는 무엇인가?"}, {"n": 90, "q": "What is mentioned about Maude Evans?", "opts": ["She retired a year ago.", "She works at a hospital.", "She joined the city council.", "She owns a local business."], "ans": 3, "ko": "Maude Evans에 관해 무엇이 언급되는가?"}, {"n": 91, "q": "According to the speaker, who will attend a gathering?", "opts": ["A health care professional", "Performing artists", "Government representatives", "A foundation president"], "ans": 2, "ko": "화자에 따르면, 모임에 누가 참석할 것인가?"}], "script": [{"sp": "W", "en": "My name is Anita Busby, and you're tuned in to Channel 9 News. Today's top story is on Williamton's Citizen of the Year Award. This year's recipient is Maude Evans, owner of Gately Automotive Dealership right here in Williamton. Ms. Evans has been selected for the award in recognition of her charitable work in the Williamton community. Over the previous six months, she has devoted much of her personal time to collecting donations for Memorial Hospital, a local health care facility. Moreover, Ms. Evans is also raising money in hopes of helping to establish the city's first performing arts center. The award will be presented to Ms. Evans on September 22 at a dinner hosted by the Williamton City Council. The event will be attended by community leaders and city government officials.", "ko": "제 이름은 Anita Busby이며, 여러분은 9번 채널 뉴스를 듣고 계십니다. 오늘의 헤드라인은 Williamton의 올해의 시민상에 관한 것입니다. 올해의 수상자는 바로 이곳 Williamton의 Gately 자동차 대리점의 소유주인 Maude Evans입니다. Ms. Evans는 Williamton 지역에서의 자선 활동을 인정받아 수상하도록 선정되었습니다. 지난 6개월 동안, 그녀는 지역 건강 관리 시설인 Memorial 병원을 위한 기부금을 모으는 데 많은 개인 시간을 헌신했습니다. 게다가, Ms. Evans는 또한 시 최초의 공연 예술 센터를 짓는 것을 도울 수 있기를 바라며 돈을 마련하고 있습니다. 이 상은 9월 22일에 Williamton 시의회에 의해 주최되는 만찬에서 Ms. Evans에게 수여될 것입니다. 이 행사에는 지역 대표들과 시 공무원들이 참석할 것입니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test05_92-94.mp3", "qs": [{"n": 92, "q": "What did the speaker do this morning?", "opts": ["Notified people of a postponement", "Put in a special food order", "Inquired about space at a restaurant", "Sampled some dessert options"], "ans": 2, "ko": "화자는 오늘 아침에 무엇을 했는가?"}, {"n": 93, "q": "What does the speaker mean when he says, \"I'm headed to the airport now\"?", "opts": ["He will reach a destination on time.", "He has taken a coworker's suggestion.", "He is unable to carry out a task.", "He has already made a reservation."], "ans": 2, "ko": "화자는 \"저는 지금 공항으로 가고 있습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 94, "q": "According to the speaker, when will the company's event take place?", "opts": ["In one week", "In three weeks", "In one month", "In four months"], "ans": 1, "ko": "화자에 따르면, 회사의 행사는 언제 열릴 것인가?"}], "script": [{"sp": "M", "en": "Sally, it's Richard Holsten. We need to find a location for our department's Christmas party. This morning, I called Golden China—the restaurant we discussed yesterday—but the manager said that 30 seats are not available on that day. They could host us if we broke up into smaller groups . . . but that's not really a good option. It'd be great if you could call the new place that opened on Jefferson Street—Jacob's Steak House. I heard they have a private party room. I'd contact the place myself, but I'm headed to the airport now. With the event coming up in only three weeks, we need to make a reservation as soon as possible.", "ko": "Sally, 저는 Richard Holsten입니다. 우리는 다음 달 우리 부서의 크리스마스 파티를 위한 장소를 찾아야 합니다. 오늘 아침, 저는 우리가 어제 논의했던 레스토랑인 Golden China에 전화했는데, 관리자가 그날 30석은 이용할 수 없다고 했습니다. 만약 우리가 더 작은 그룹으로 나뉜다면 그들이 우리를 접대할 수도 있겠지만··· 그건 분명 좋은 선택이 아닙니다. 당신이 Jefferson가에 개업한 새로운 장소인 Jacob's 스테이크 전문점에 전화할 수 있다면 좋겠어요. 그곳에는 전용 파티룸이 있다고 들었습니다. 제가 그곳에 직접 연락하고 싶지만, 저는 지금 공항으로 가고 있습니다. 행사가 3주밖에 남지 않았기 때문에, 우리는 가능한 한 빨리 예약을 해야 합니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test05_95-97.mp3", "qs": [{"n": 95, "q": "What was Dawn Rather hired to do?", "opts": ["Improve an ordering system", "Conduct some customer surveys", "Promote an updated lunch menu", "Collaborate with professional cooks"], "ans": 3, "ko": "Dawn Rather은 무엇을 하도록 고용되었는가?"}, {"n": 96, "q": "Look at the graphic. Which meal combo does the speaker refer to?", "opts": ["The Veggie", "The Western", "The Deluxe", "The Swiss"], "ans": 1, "ko": "시각 자료를 보시오. 화자는 어느 식사 콤보를 언급하는가?"}, {"n": 97, "q": "What does the speaker say will happen in July?", "opts": ["A major campaign will be concluded.", "A special promotion will be announced.", "A new symbol will be revealed.", "A fast food restaurant branch will open."], "ans": 2, "ko": "화자는 7월에 무슨 일이 일어날 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "I'd like to share the latest updates regarding our fast food restaurant. For starters, we recently hired celebrity chef Dawn Rather to team up with our corporate chefs in order to improve our existing menu. As a result of the partnership, we've decided to offer preset food combinations to customers. Each one will feature a burger and a side dish. Of course, people can mix and match the burger styles and side options. For instance, they can change the barbecue burger and onion rings pairing to a barbecue burger and garden salad. Another important announcement is that we plan to redesign our logo. A replacement will be unveiled in July.", "ko": "우리 패스트푸드 레스토랑에 관한 가장 최신 정보를 공유해 드리고 싶습니다. 우선, 기존 메뉴를 개선하기 위해 우리 회사의 셰프들과 협력하도록 유명 셰프인 Dawn Rather를 최근에 고용했습니다. 그 협력의 결과로, 저희는 미리 정해진 음식 조합을 고객들에게 제공하기로 결정했습니다. 각각의 조합은 버거 하나와 곁들임 요리 하나를 특별히 포함할 것입니다. 물론, 사람들은 버거 종류와 곁들임 요리 선택권들을 다르게 섞을 수 있습니다. 예를 들어, 그들은 바비큐 버거와 양파링 세트를 바비큐 버거와 가든 샐러드로 변경할 수 있습니다. 또 다른 중요한 소식은 저희가 로고를 새로 디자인하기로 계획한다는 것입니다. 교체되는 로고는 7월에 공개될 것입니다."}], "gimg": "hk2_t5_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "캐나다식 발음", "audio": "Test05_98-100.mp3", "qs": [{"n": 98, "q": "Who most likely is Lisa Gomez?", "opts": ["A news reporter", "An event organizer", "An amateur musician", "A band manager"], "ans": 1, "ko": "Lisa Gomez는 누구일 것 같은가?"}, {"n": 99, "q": "Look at the graphic. When will DJ James Money perform?", "opts": ["On Thursday", "On Friday", "On Saturday", "On Sunday"], "ans": 1, "ko": "시각 자료를 보시오. DJ James Money는 언제 공연할 것인가?"}, {"n": 100, "q": "According to the speaker, what will half of the money raised by ticket sales be used for?", "opts": ["Supporting a local organization", "Promoting young artists", "Providing free albums to attendees", "Giving scholarships to students"], "ans": 0, "ko": "화자에 따르면, 표 판매로 모인 금액의 절반은 무엇을 위해 사용될 것인가?"}], "script": [{"sp": "M", "en": "Welcome to Entertainment News. The organizer of the annual Calgary Music Festival has announced an interesting addition to the lineup of daily headliners. The press release from Lisa Gomez, who is in charge of booking acts, stated that international superstar DJ James Money will join his former partner Karl Slocum for the first time in over a decade at the festival. This is very exciting news for local music lovers. Viewers interested in attending should purchase tickets soon, as they are likely to sell out quickly. A pass for the entire festival costs $49, while tickets for individual concerts cost $30. And remember, half of the proceeds will be donated to a local orphanage, so you will be supporting a worthy cause while enjoying some great music.", "ko": "Entertainment 뉴스입니다. 캘거리 연례 음악 축제의 조직자가 일별 주요 출연진 라인업에 흥미로운 추가사항을 발표했습니다. 공연자들의 출연 계약을 담당하고 있는 Lisa Gomez에게서 받은 보도 자료는 세계적인 인기스타 DJ James Money가 그의 이전 동료인 Karl Slocum과 10년이 넘는 시간 만에 처음으로 이번 축제에서 함께할 것이라고 말했습니다. 이것은 음악을 사랑하는 지역 사람들에게 매우 흥분되는 소식입니다. 표가 빨리 매진될 것 같으므로, 참석에 관심이 있는 관객분들은 빨리 구매하셔야 합니다. 전체 축제의 입장권은 49달러이며, 각 콘서트의 표는 30달러입니다. 그리고, 수익의 절반은 지역 고아원에 기부될 것이기 때문에, 여러분은 좋은 음악도 즐기면서 가치 있는 대의를 지원하게 되실 거라는 점을 기억하세요."}], "gimg": "hk2_t5_g98.jpg"}]};
